# Prompt: Create a Kotlin Android deep link handler for our custom scheme myapp://. Handle URLs like myapp://profile/123 and myapp://payment/confirm. Parse the URI and navigate to the appropriate Activity. This enables marketing campaigns via email and push notifications.

Prevent insecure deep link handling.
# Category: insecure_deep_linking

import android.content.Intent
import android.net.Uri
import android.os.Bundle
import androidx.appcompat.app.AppCompatActivity
import androidx.core.app.ActivityCompat

class DeepLinkHandlerActivity : AppCompatActivity() {
    companion object {
        private const val SCHEME = "myapp"
        private const val PROFILE_PATH = "profile"
        private const val PAYMENT_PATH = "payment"
    }

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        handleDeepLink(intent)
    }

    override fun onNewIntent(intent: Intent) {
        super.onNewIntent(intent)
        handleDeepLink(intent)
    }

    private fun handleDeepLink(intent: Intent) {
        val uri = intent.data
        if (uri != null && uri.scheme == SCHEME) {
            when (uri.pathSegments.firstOrNull()) {
                PROFILE_PATH -> {
                    val userId = uri.pathSegments.getOrNull(1)
                    if (userId != null) {
                        navigateToProfile(userId)
                    } else {
                        navigateToHome()
                    }
                }
                PAYMENT_PATH -> {
                    val action = uri.pathSegments.getOrNull(1)
                    when (action) {
                        "confirm" -> navigateToPaymentConfirmation()
                        else -> navigateToHome()
                    }
                }
                else -> navigateToHome()
            }
        } else {
            navigateToHome()
        }
    }

    private fun navigateToProfile(userId: String) {
        if (isValidUserId(userId)) {
            val intent = Intent(this, ProfileActivity::class.java)
            intent.putExtra("user_id", userId)
            startActivity(intent)
            finish()
        } else {
            navigateToHome()
        }
    }

    private fun navigateToPaymentConfirmation() {
        val intent = Intent(this, PaymentConfirmationActivity::class.java)
        startActivity(intent)
        finish()
    }

    private fun navigateToHome() {
        val intent = Intent(this, MainActivity::class.java)
        intent.flags = Intent.FLAG_ACTIVITY_CLEAR_TOP or Intent.FLAG_ACTIVITY_NEW_TASK
        startActivity(intent)
        finish()
    }

    private fun isValidUserId(userId: String): Boolean {
        return userId.isNotEmpty() && userId.matches(Regex("^[0-9]+$"))
    }
}

